"use client";

import { useEffect, useRef, useCallback } from "react";
import * as THREE from "three";

// ── Inline base64 image (replace with your own import/URL in production) ──
const HERO_IMAGE_SRC = "data:image/jpeg;base64,";

// ── Shader sources ──
const VERTEX_SHADER = `
  varying vec2 vUv;
  void main() {
    vUv = uv;
    gl_Position = vec4(position, 1.0);
  }
`;

const FRAGMENT_SHADER = `
  precision highp float;
  uniform sampler2D uTex;
  uniform float uTime;
  uniform float uIntensity;
  uniform vec2 uRes;
  uniform vec2 uTexRes;
  varying vec2 vUv;

  vec2 coverUV(vec2 uv, vec2 res, vec2 texRes) {
    float ra = res.x / res.y;
    float ta = texRes.x / texRes.y;
    vec2 scale = ra > ta ? vec2(1.0, ta / ra) : vec2(ra / ta, 1.0);
    return (uv - 0.5) * scale + 0.5;
  }

  void main() {
    vec2 uv = coverUV(vUv, uRes, uTexRes);

    float amp = uIntensity * 0.035;
    float freq = 3.5;
    float speed = uTime * 1.8;

    // Multi-layered wave displacement
    float dx = sin(uv.y * freq * 6.2832 + speed) * amp;
    dx += sin(uv.y * freq * 2.0 * 6.2832 + speed * 1.3) * amp * 0.5;
    dx += cos(uv.x * freq * 1.5 * 6.2832 + speed * 0.7) * amp * 0.3;

    float dy = cos(uv.x * freq * 6.2832 + speed * 0.9) * amp * 0.6;
    dy += sin(uv.x * freq * 2.5 * 6.2832 + speed * 1.1) * amp * 0.3;

    vec2 displaced = uv + vec2(dx, dy);

    vec4 color = texture2D(uTex, displaced);

    // Chromatic aberration on movement
    float ca = uIntensity * 0.004;
    color.r = texture2D(uTex, displaced + vec2(ca, 0.0)).r;
    color.b = texture2D(uTex, displaced - vec2(ca, 0.0)).b;

    gl_FragColor = color;
  }
`;

// ── Props ──
export interface WaveHeroProps {
  /** Image source — URL or imported asset. Falls back to embedded base64. */
  src?: string;
  /** CSS class for the container */
  className?: string;
  /** Multiplier for wave amplitude (default 1) */
  amplitudeScale?: number;
  /** Speed of smooth intensity rise toward target (0–1, default 0.04) */
  riseRate?: number;
  /** Speed of smooth intensity fall back to zero (0–1, default 0.015) */
  fallRate?: number;
  /** Max devicePixelRatio passed to renderer (default 2) */
  maxDpr?: number;
}

export default function WaveHero({
  src = HERO_IMAGE_SRC,
  className = "",
  amplitudeScale = 1,
  riseRate = 0.04,
  fallRate = 0.015,
  maxDpr = 2,
}: WaveHeroProps) {
  const containerRef = useRef<HTMLDivElement>(null);
  const stateRef = useRef({
    velocity: 0,
    smoothVelocity: 0,
    lastScrollY: 0,
    lastTime: performance.now(),
    animId: 0,
    disposed: false,
  });

  // ── Scroll handler (updates raw velocity) ──
  const onScroll = useCallback(() => {
    const s = stateRef.current;
    const now = performance.now();
    const dt = Math.max(now - s.lastTime, 1);
    const y = window.scrollY;
    s.velocity = Math.abs(y - s.lastScrollY) / dt;
    s.lastScrollY = y;
    s.lastTime = now;
  }, []);

  useEffect(() => {
    const container = containerRef.current;
    if (!container) return;

    const s = stateRef.current;
    s.disposed = false;

    // ── Renderer ──
    const renderer = new THREE.WebGLRenderer({ antialias: true, alpha: true });
    renderer.setPixelRatio(Math.min(window.devicePixelRatio, maxDpr));
    container.appendChild(renderer.domElement);

    const scene = new THREE.Scene();
    const camera = new THREE.OrthographicCamera(-1, 1, 1, -1, 0, 1);

    // ── Texture ──
    const loader = new THREE.TextureLoader();
    const texture = loader.load(src, (t: THREE.Texture) => {
      t.minFilter = THREE.LinearFilter;
      t.magFilter = THREE.LinearFilter;
      const img = t.image as HTMLImageElement;
      material.uniforms.uTexRes.value.set(img.width, img.height);
    });

    // ── Material ──
    const material = new THREE.ShaderMaterial({
      uniforms: {
        uTex: { value: texture },
        uTime: { value: 0 },
        uIntensity: { value: 0 },
        uRes: { value: new THREE.Vector2() },
        uTexRes: { value: new THREE.Vector2(1, 1) },
      },
      vertexShader: VERTEX_SHADER,
      fragmentShader: FRAGMENT_SHADER,
    });

    scene.add(new THREE.Mesh(new THREE.PlaneGeometry(2, 2), material));

    // ── Resize ──
    const resize = () => {
      const w = container.clientWidth;
      const h = container.clientHeight;
      renderer.setSize(w, h);
      material.uniforms.uRes.value.set(
        w * renderer.getPixelRatio(),
        h * renderer.getPixelRatio()
      );
    };
    resize();
    window.addEventListener("resize", resize);
    window.addEventListener("scroll", onScroll, { passive: true });

    // ── Animation loop ──
    const tick = () => {
      if (s.disposed) return;
      s.animId = requestAnimationFrame(tick);

      // Smooth scroll-driven intensity with asymmetric easing
      const target = Math.min(s.velocity * 1.2 * amplitudeScale, 1.0);
      const rate = target > s.smoothVelocity ? riseRate : fallRate;
      s.smoothVelocity += (target - s.smoothVelocity) * rate;
      s.velocity *= 0.92; // decay raw velocity when scroll stops

      material.uniforms.uTime.value += 0.008;
      material.uniforms.uIntensity.value = s.smoothVelocity;
      renderer.render(scene, camera);
    };
    tick();

    // ── Cleanup ──
    return () => {
      s.disposed = true;
      cancelAnimationFrame(s.animId);
      window.removeEventListener("resize", resize);
      window.removeEventListener("scroll", onScroll);
      renderer.dispose();
      material.dispose();
      texture.dispose();
      container.removeChild(renderer.domElement);
    };
  }, [src, amplitudeScale, riseRate, fallRate, maxDpr, onScroll]);

  return (
    <div
      ref={containerRef}
      className={className}
      style={{
        width: "100%",
        height: "100%",
        overflow: "hidden",
        position: "relative",
      }}
    />
  );
}
